pub struct ChartParser;impl ChartParser &#123;    pub fn parse_chart(pairs: Pairs&lt;Rule&gt;) -&gt; Chart &#123;        let root_pair = pairs            .into_iter()            .next()            .expect(&quot;parser: expect chart, found nothing&quot;);        if root_pair.as_rule() != Rule::chart &#123;            panic!(&quot;parser: expect chart, found &#123;:?&#125;&quot;, root_pair);        &#125;        let mut note_collections = Vec::&lt;NoteCollection&gt;::new();        let mut timings = Vec::&lt;Timing&gt;::new();        let mut time = 0.0;        timings.push(Timing::default());        for it in root_pair.into_inner() &#123;            let rule = it.as_rule();            match rule &#123;                Rule::tempo_change =&gt; time_parser::parse_tempo_change(it, &amp;mut timings, time),                Rule::subdivision_change =&gt; &#123;                    time_parser::parse_subdivision_change(it, &amp;mut timings, time)                &#125;                Rule::note_collection =&gt; &#123;                    note_collections.push(note_parser::parse_note_collection(it, &amp;timings, time))                &#125;                Rule::time_step =&gt; time += time_parser::parse_time_step(&amp;timings),                Rule::COMMENT | Rule::WHITESPACE | Rule::eof | Rule::eoi =&gt; &#123;&#125;                _ =&gt; &#123;                    panic!(&quot;parser: unexpected rule &#123;:?&#125;&quot;, rule)                &#125;            &#125;;        &#125;        Chart &#123;            note_collections,            timings,        &#125;    &#125;&#125;
